const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x111827);this.add.rectangle(W/2,H/2,W-40,20,0x374151);this.items=this.physics.add.group();this.score=0;this.ui=this.add.text(10,10,'Sorted:0');this.good=0x22c55e;this.bad=0xef4444;this.left=this.add.rectangle(80,H-70,120,44,this.good).setInteractive();this.right=this.add.rectangle(W-80,H-70,120,44,this.bad).setInteractive();this.add.text(80,H-78,'GOOD',{fontSize:'18px'}).setOrigin(.5);this.add.text(W-80,H-78,'BAD',{fontSize:'18px'}).setOrigin(.5);this.choice='L';this.left.on('pointerdown',()=>this.choice='L');this.right.on('pointerdown',()=>this.choice='R');this.time.addEvent({delay:700,loop:true,callback:()=>{const good=Math.random()>0.5;const i=this.add.circle(30,H/2,10,good?this.good:this.bad);i.good=good;this.physics.add.existing(i);i.body.setVelocityX(140);this.items.add(i);}});this.r=this.input.keyboard.addKey('R');}update(){if(this.r.isDown)this.scene.restart();this.items.getChildren().forEach(i=>{if(i.x>W-40){const ok=(i.good&&this.choice==='L')||(!i.good&&this.choice==='R');if(ok)this.score++;else this.score=Math.max(0,this.score-1);this.ui.setText('Sorted:'+this.score);i.destroy();}});if(this.score>=25&&!this.over){this.over=true;this.add.text(W/2,H/2,'CLEAR R').setOrigin(.5);}}
}
new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,physics:{default:'arcade'},scene:[S]});
